-- =====================================================
-- 2. Структурированные критерии перехода shoulder_phf_conservative
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Старт с Фазы 1 (нет prehab). Фаза 4 (терминальная) НЕСЁТ критерии завершения.
--    measurement (vas_score+pain) в источнике как критерий перехода НЕ задан → measurement-критериев
--    нет; все числа по объёму движений и срокам → instructor_check (порог в тексте label).
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (ранняя защищённая мобилизация → восстановление амплитуды)
  (1, 'doctor_callus_p1',       'Врач подтвердил по снимку начало сращения (формирование костной мозоли) — ключевой критерий, платформа рентген не делает', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'no_secondary_disp_p1',   'Куратор подтверждает отсутствие признаков вторичного смещения по последнему снимку или осмотру врача',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'weeks_since_3_p1',       'Прошло не менее 3 недель от травмы (нижняя граница окна; при риск-гейте — по решению врача)',                                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'sleep_no_wake_p1',       'Боль в покое стихла настолько, что вы спите без частых пробуждений из-за плеча',                                             'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Стихла ли боль в покое настолько, что вы спите без частых пробуждений из-за плеча?', 'Сравните ночи в начале и сейчас', 40::smallint, TRUE),
  (1, 'free_elbow_hand_p1',     'Свободно двигаете локтем, кистью и пальцами без боли в плече',                                                               'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете ли вы свободно двигать локтем, кистью и пальцами без боли в плече?', 'Согните и разогните локоть, пошевелите кистью и пальцами', 50::smallint, TRUE),

  -- Фаза 2 → Фаза 3 (восстановление амплитуды → укрепление)
  (2, 'doctor_consol_active_p2','Лечащий врач подтверждает, что сращение достаточно для активной нагрузки',                                                   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'assisted_flexion_90_p2', 'Подъём руки вперёд при поддержке не менее 90°',                                                                             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
