  -- Фаза 4 (терминальная) — критерии завершения протокола / возврата к функции
  (4, 'functional_rom_p4',      'Активная амплитуда восстановлена до функционального уровня (порог индивидуален, решает куратор очно)',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
